UPDATE "ec_pages" SET "source_seo" = '{"title":"Akdeniz University - RoadtoStudy","description":"Akdeniz University was established in Antalya on July 20, 1982, by Decree Law No. 41. Initially operating as units affiliated with Ege and Çukurova","robots":"follow, index, max-snippet:-1, max-video-preview:-1, max-image-preview:large","ogTitle":"Akdeniz University - RoadtoStudy","ogDescription":"Akdeniz University was established in Antalya on July 20, 1982, by Decree Law No. 41. Initially operating as units affiliated with Ege and Çukurova","ogImage":null,"twitterCard":"summary_large_image","twitterTitle":"Akdeniz University - RoadtoStudy","twitterDescription":"Akdeniz University was established in Antalya on July 20, 1982, by Decree Law No. 41. Initially operating as units affiliated with Ege and Çukurova","canonicalPath":"/en/akdeniz-university/","hreflang":[{"hreflang":"tr","href":"/akdeniz-universitesi-tanitim-kampus-rehberi/"},{"hreflang":"en","href":"/en/akdeniz-university/"}],"jsonLd":[{"@context":"https://schema.org","@graph":[{"@type":["Organization","Person"],"@id":"https://roadtostudy.com/#person","name":"Road to Study - Turkey University Guide for Students","url":"https://roadtostudy.com","logo":{"@type":"ImageObject","@id":"https://roadtostudy.com/#logo","url":"https://roadtostudy.com/wp-content/uploads/2025/02/Kare-Logo-e1740739634958.png","contentUrl":"https://roadtostudy.com/wp-content/uploads/2025/02/Kare-Logo-e1740739634958.png","caption":"Road to Study - Turkey University Guide for Students","inLanguage":"en-US","width":"450","height":"445"},"image":{"@id":"https://roadtostudy.com/#logo"}},{"@type":"WebSite","@id":"https://roadtostudy.com/#website","url":"https://roadtostudy.com","name":"Road to Study - Turkey University Guide for Students","alternateName":"Road to Study in Turkey","publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"en-US"},{"@type":"WebPage","@id":"https://roadtostudy.com/en/akdeniz-university/#webpage","url":"https://roadtostudy.com/en/akdeniz-university/","name":"Akdeniz University - RoadtoStudy","datePublished":"2025-10-06T10:40:28+03:00","dateModified":"2025-10-06T10:40:29+03:00","isPartOf":{"@id":"https://roadtostudy.com/#website"},"inLanguage":"en-US"},{"@type":"Person","@id":"https://roadtostudy.com/en/author/busra/","name":"busra","url":"https://roadtostudy.com/en/author/busra/","image":{"@type":"ImageObject","@id":"https://secure.gravatar.com/avatar/a3c0f700b03ed22f8ab3a40880c2b539035a9a6e21bb16550f65e22a0ff39809?s=96&amp;d=mm&amp;r=g","url":"https://secure.gravatar.com/avatar/a3c0f700b03ed22f8ab3a40880c2b539035a9a6e21bb16550f65e22a0ff39809?s=96&amp;d=mm&amp;r=g","caption":"busra","inLanguage":"en-US"}},{"@type":"Article","headline":"Akdeniz University - RoadtoStudy","keywords":"Akdeniz University","datePublished":"2025-10-06T10:40:28+03:00","dateModified":"2025-10-06T10:40:29+03:00","author":{"@id":"https://roadtostudy.com/en/author/busra/","name":"busra"},"publisher":{"@id":"https://roadtostudy.com/#person"},"description":"Akdeniz University was established in Antalya on July 20, 1982, by Decree Law No. 41. Initially operating as units affiliated with Ege and Çukurova","name":"Akdeniz University - RoadtoStudy","@id":"https://roadtostudy.com/en/akdeniz-university/#richSnippet","isPartOf":{"@id":"https://roadtostudy.com/en/akdeniz-university/#webpage"},"inLanguage":"en-US","mainEntityOfPage":{"@id":"https://roadtostudy.com/en/akdeniz-university/#webpage"}}]}]}', "content_html" = '<h2 class="wp-block-heading">History and Vision of the University</h2>



<p class="wp-block-paragraph">Akdeniz University was established in Antalya on July 20, 1982, by Decree Law No. 41. Initially operating as units affiliated with Ege and Çukurova Universities, it later became an independent institution and is now one of the leading educational centers in the Mediterranean region. Under the leadership of Rector Prof. Dr. Özlenen Özkan (since August 7, 2020), the university embraces the vision <strong>“Illuminating the Future with Science.”</strong> Its mission is to educate innovative, critical-thinking individuals who contribute to society. With approximately <strong>65,000 students</strong> (YÖK Atlas, 2022–2023), Akdeniz University ranks in the <strong>801–1000 band in the Times Higher Education 2025</strong> rankings. The university plays a pioneering role in the region’s development, particularly in <strong>tourism, agriculture, and health.</strong></p>



<h2 class="wp-block-heading">Education</h2>



<p class="wp-block-paragraph">Akdeniz University offers academic diversity through <strong>24 faculties</strong>, including Medicine, Dentistry, Pharmacy, Veterinary, Science, Literature, Economics and Administrative Sciences, Engineering, Education, Law, Theology, Communication, Fine Arts, Health Sciences, Sports Sciences, Agriculture, Tourism, Technology, Architecture, Nursing, Aquaculture, Applied Sciences, Manavgat Tourism, and Kemer Applied Sciences. There are <strong>over 130 undergraduate</strong> and <strong>more than 150 graduate programs.</strong> Medicine, Tourism, and Agriculture stand out among them. The university employs around <strong>2,500 faculty members</strong>, consisting of expert academics. The educational model integrates theoretical and practical learning; some programs are offered in English. With <strong>over 100 laboratories</strong> and <strong>40 research centers</strong> (such as Akdeniz Technopark), students gain strong practical experience. Akdeniz University is active in TÜBİTAK projects and recognized for its scientific productivity. For more information, you can visit the official <a href="http://www.akdeniz.edu.tr/" data-type="link" data-id="http://www.akdeniz.edu.tr/" target="_blank" rel="noopener">Akdeniz University</a> website.</p>



<h2 class="wp-block-heading">Campus and Technological Infrastructure</h2>



<p class="wp-block-paragraph">The main campus of Akdeniz University is located in <strong>Konyaaltı, Antalya</strong>, covering an area of <strong>3.7 million m².</strong> Additional campuses are located in Alanya, Manavgat, Kemer, and other districts. The campus consists of <strong>over 100 buildings</strong> and <strong>400,000 m² of indoor space</strong>, designed with modern and green architecture. High-speed internet and smart classrooms form the basis of its technological infrastructure. The <strong>Central Library</strong> offers access to <strong>over 500,000 printed materials</strong> and <strong>more than 1 million digital publications</strong>, with a capacity of over 2,000 people. Research facilities include advanced laboratories, particularly in agriculture and health sciences, providing a strong foundation for scientific work.</p>



<h2 class="wp-block-heading">Accommodation</h2>



<p class="wp-block-paragraph">Akdeniz University offers dormitory facilities both <strong>on and around the campus</strong> in collaboration with <strong>KYK (Credit and Dormitories Institution).</strong> The Konyaaltı Campus dormitories accommodate over <strong>7,000 students.</strong> Rooms are designed for 2–6 people and include beds, wardrobes, desks, and internet access. Dormitories feature laundry rooms, kitchens, and study areas. Security is ensured through <strong>24-hour surveillance</strong>, and cleaning is carried out regularly. Canteens provide essential needs. Applications are made online through the KYK system, and scholarship students receive additional support. The dormitories’ proximity to the campus offers great convenience.</p>



<h2 class="wp-block-heading">Social Life</h2>



<p class="wp-block-paragraph">Akdeniz University offers a vibrant social environment. The green areas of the Konyaaltı Campus and its proximity to the Mediterranean Sea create a peaceful atmosphere. Sports facilities include an <strong>Olympic swimming pool, basketball courts, and tennis courts</strong>—with university teams achieving success in various tournaments. Dining halls provide daily meals; vegan options are limited but can be arranged upon request. With <strong>over 80 student clubs</strong> (e.g., the AÜ Mountaineering Club), the university hosts conferences, exhibitions, and festivals. The <strong>“Akdeniz Spring Festival”</strong> brings the campus to life with concerts and cultural events. Antalya’s natural and touristic beauty further enriches social life. Special events are organized for international students.</p>



<p class="wp-block-paragraph">For more information about university life in Turkey, international students can visit the <strong><a href="https://roadtostudy.com" data-type="link" data-id="https://roadtostudy.com">Road to Study</a></strong> platform.</p>



<h2 class="wp-block-heading">Cultural Adaptation for International Students</h2>



<p class="wp-block-paragraph">Akdeniz University hosts <strong>over 2,500 international students from more than 60 countries.</strong> The <strong>International Relations Office</strong> provides orientation and counseling services. Turkish language courses are offered by <strong>TÖMER</strong>, from A1 to C1 levels, to ease cultural adaptation. Through the <strong>Erasmus+ and Mevlana</strong> programs, the university collaborates with <strong>over 300 partner institutions worldwide.</strong> Events like <strong>“International Culture Day”</strong> foster cultural exchange. A mentorship system helps newcomers integrate smoothly into campus life. Turkey’s cultural heritage offers international students a truly unique experience.</p>



<h2 class="wp-block-heading">Health Services and Security</h2>



<p class="wp-block-paragraph">Akdeniz University houses the <strong>Faculty of Medicine Hospital</strong>, one of the largest healthcare complexes in the region. The <strong>Health Center</strong> provides weekday consultations and emergency care, supported by <strong>24/7 ambulance service.</strong> Psychological counseling is available through individual therapy sessions, which can be booked online. Campus security is maintained with <strong>24-hour surveillance systems and personnel</strong>, and all entry-exit points are monitored. Regular fire drills are conducted, and safety equipment is available in all buildings.</p>



<h2 class="wp-block-heading">Transportation</h2>



<p class="wp-block-paragraph">The <strong>Konyaaltı Campus</strong> of Akdeniz University is located <strong>10 km from the city center</strong> of Antalya and is accessible by tram (AntRay), bus, and minibus. <strong>Free shuttle (ring) services</strong> operate within the campus according to class schedules. There are <strong>bicycle lanes and parking areas</strong> for easy mobility. The <strong>Antalya Airport</strong> is 15 km away, and public transport fares are discounted with the <strong>AntalyaKart</strong>. Access to the city center is convenient and affordable.</p>



<h2 class="wp-block-heading">Student Support Services</h2>



<p class="wp-block-paragraph">Akdeniz University’s <strong>Career Center</strong> provides internship and job opportunities and organizes <strong>Career Days.</strong> Academic advisors guide students in course selection and career planning. The <strong>Psychological Support Unit</strong> offers free therapy sessions for mental well-being. The <strong>Disabled Student Office</strong> ensures accessibility and exam arrangements. The <strong>Scholarship Coordination Office</strong> manages financial aid, and mentorship programs support new students in adapting to university life.</p>



