-izmir-tinaztepe-universitesi/#sosyal-yasam"},{"@context":"https://schema.org","@type":"SiteNavigationElement","@id":"#rank-math-toc","name":"Uluslararası Öğrenciler İçin Kültürel Uyum","url":"https://roadtostudy.com/universiteler-izmir-tinaztepe-universitesi/#uluslararasi-ogrenciler-icin-kulturel-uyum"},{"@context":"https://schema.org","@type":"SiteNavigationElement","@id":"#rank-math-toc","name":"Sağlık Hizmetleri ve Güvenlik","url":"https://roadtostudy.com/universiteler-izmir-tinaztepe-universitesi/#saglik-hizmetleri-ve-guvenlik"},{"@context":"https://schema.org","@type":"SiteNavigationElement","@id":"#rank-math-toc","name":"Ulaşım","url":"https://roadtostudy.com/universiteler-izmir-tinaztepe-universitesi/#ulasim"},{"@context":"https://schema.org","@type":"SiteNavigationElement","@id":"#rank-math-toc","name":"Öğrenci Destek Hizmetleri","url":"https://roadtostudy.com/universiteler-izmir-tinaztepe-universitesi/#ogrenci-destek-hizmetleri"}],{"@type":["Organization","Person"],"@id":"https://roadtostudy.com/#person","name":"Road to Study - Turkey University Guide for Students","url":"https://roadtostudy.com","logo":{"@type":"ImageObject","@id":"https://roadtostudy.com/#logo","url":"https://roadtostudy.com/wp-content/uploads/2025/02/Kare-Logo-e1740739634958.png","contentUrl":"https://roadtostudy.com/wp-content/uploads/2025/02/Kare-Logo-e1740739634958.png","caption":"Road to Study - Turkey University Guide for Students","inLanguage":"tr","width":"450","height":"445"},"image":{"@id":"https://roadtostudy.com/#logo"}},{"@type":"WebSite","@id":"https://roadtostudy.com/#website","url":"https://roadtostudy.com","name":"Road to Study - Turkey University Guide for Students","alternateName":"Road to Study in Turkey","publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"tr"},{"@type":"WebPage","@id":"https://roadtostudy.com/universiteler-izmir-tinaztepe-universitesi/#webpage","url":"https://roadtostudy.com/universiteler-izmir-tinaztepe-universitesi/","name":"İzmir T